**代码框架**:
```typescript
// src/agents/security/sandbox.ts
export class AgentSandbox {
  private allowedPaths: Set<string>;
  private forbiddenCommands: Set<string>;

  constructor() {
    this.allowedPaths = new Set([
      process.cwd(),
      '/tmp/ai-dev-team'
    ]);

    this.forbiddenCommands = new Set([
      'rm -rf',
      'mkfs',
      'dd',
      'chmod 777'
    ]);
  }

  // 检查文件访问
  canAccessPath(path: string): boolean {
    const resolved = path.resolve(path);
    return Array.from(this.allowedPaths).some(allowed => 
      resolved.startsWith(allowed)
    );
  }

  // 检查命令执行
  canExecuteCommand(command: string): boolean {
    return !Array.from(this.forbiddenCommands).some(forbidden =>
      command.includes(forbidden)
    );
  }
}

// 在BaseAgent中集成
export abstract class BaseAgent {
  protected sandbox: AgentSandbox;

  constructor() {
    this.sandbox = new AgentSandbox();
  }

  async safeExecuteCommand(command: string): Promise<string> {
    if (!this.sandbox.canExecuteCommand(command)) {
      throw new SecurityError(`命令被沙箱阻止: ${command}`);
    }

    // 执行命令
    return execSync(command, { encoding: 'utf-8' });
  }
}
```

